#include <algorithm>
#include <iostream>
#include <string>
#include <vector>

struct Record { std::string name; int score; };

int main() {
    std::size_t count{};
    if (!(std::cin >> count) || count > 30) return 1;
    std::vector<Record> records(count);
    for (auto& record : records) if (!(std::cin >> record.name >> record.score)) return 1;
    std::sort(records.begin(), records.end(), [](const Record& a, const Record& b) { return a.score != b.score ? a.score > b.score : a.name < b.name; });
    for (std::size_t i = 0; i < records.size(); ++i) { if (i) std::cout << ' '; std::cout << records[i].name; }
    std::cout << '\n';
}
